import { useState, useEffect } from 'react';
import { searchProduct } from '../services/openFoodFacts';

function IngredientList({ ingredients, onAddToCart }) {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchAll = async () => {
      setLoading(true);
      const results = await Promise.all(
        ingredients.map(async (ing) => {
          let product = null;
try {
  product = await searchProduct(ing.search);
} catch (e) {
  console.log('OFF unavailable for:', ing.name);
}
return {
  ...ing,
  realName: product ? product.product_name || ing.name : ing.name,
  brand: product ? product.brands || '' : '',
  fromOFF: !!product,
  price: (Math.random() * 2.5 + 0.49).toFixed(2)
};
        })
      );
      setProducts(results);
      setLoading(false);
    };
    fetchAll();
  }, [ingredients]);

  if (loading) return <div className="loading">Searching Open Food Facts...</div>;

  return (
    <div className="ingredient-list">
      <h2>Ingredients Found</h2>
      <p>{products.filter(p => p.fromOFF).length} of {products.length} matched on Open Food Facts</p>
      {products.map((item, i) => (
        <div key={i} className="ing-card">
          <span className="ing-icon">{item.icon}</span>
          <div className="ing-info">
            <div className="ing-name">{item.realName}</div>
            <div className="ing-meta">{item.brand && item.brand + ' · '}{item.qty}</div>
            <span className={item.fromOFF ? 'badge-green' : 'badge-yellow'}>
              {item.fromOFF ? 'Open Food Facts' : 'AI estimate'}
            </span>
          </div>
          <div className="ing-price">£{item.price}</div>
        </div>
      ))}
      <button className="main-btn" onClick={() => onAddToCart(products)}>
        Add all to cart →
      </button>
    </div>
  );
}

export default IngredientList;
